1067→        const currentTotalScale = fitScale * currentViewport.scale;
1068→        const currentTotalX = fitOffsetX + currentViewport.x;
1069→        const currentTotalY = fitOffsetY + currentViewport.y;
1070→        const nextTotalScale = fitScale * nextScale;
1071→        const worldPoint = {
1072→            x: (anchor.x - currentTotalX) / currentTotalScale,
1073→            y: (anchor.y - currentTotalY) / currentTotalScale
1074→        };
1075→        updateViewport({
1076→            scale: nextScale,
1077→            x: anchor.x - worldPoint.x * nextTotalScale - fitOffsetX,
1078→            y: anchor.y - worldPoint.y * nextTotalScale - fitOffsetY
1079→        });
1080→    }, [fitScale, fitOffsetX, fitOffsetY, updateViewport]);
