.editorFooter {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.65rem;
}

.wordCount {
    color: color-mix(in srgb, var(--atelier-ink) 72%, transparent);
    font-size: 0.76rem;
}

.shareButton {
    border: 1px solid rgba(18, 24, 31, 0.18);
    border-radius: 12px;
    background: linear-gradient(120deg, #ff8a4d, #ff6b3d);
    color: #fff;
    padding: 0.45rem 0.82rem;
    font-size: 0.82rem;
    font-weight: 650;
    cursor: pointer;
    transition: transform 140ms ease, box-shadow 160ms ease;
}

.shareButton:hover {
    transform: translateY(-1px);
    box-shadow: 0 10px 20px rgba(255, 107, 61, 0.24);
}

.shareButtonDisabled {
    opacity: 0.5;
    cursor: not-allowed;
    box-shadow: none;
    transform: none;
}

/* ── Kept for canvas viewer toolbar ── */

.toolbarDock {
    position: relative;

