}

.snippetInput:focus {
    outline: none;
    border-color: #5ad39f;
    box-shadow: 0 0 0 2px rgba(90, 211, 159, 0.26);
}

.snippetActions {
    display: inline-flex;
    gap: 0.38rem;
}

.paletteWrap {
    display: flex;
    flex-direction: column;
    gap: 0.34rem;
}

.paletteGroup {
    display: flex;
    flex-direction: column;
    gap: 0.22rem;
}

.paletteLabel {
    font-size: 0.68rem;
