}

.colorSwatches {
    display: inline-flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.32rem;
}

.colorSwatch {
    width: 22px;
    height: 22px;
    border-radius: 999px;
    border: 1px solid rgba(20, 24, 29, 0.2);
    cursor: pointer;
}

.colorSwatchActive {
    box-shadow: 0 0 0 2px rgba(255, 255, 255, 0.95), 0 0 0 4px rgba(90, 211, 159, 0.58);
}

.customColorLabel {
