.sizeRange {
    width: 100%;
}

.toolHint {
    font-size: 0.68rem;
    color: color-mix(in srgb, var(--atelier-ink) 70%, transparent);
}

.selectionPanel {
    display: flex;
    flex-direction: column;
    gap: 0.46rem;
}

.styleCarousel {
    display: flex;
    flex-direction: column;
    gap: 0.42rem;
}

.fontChip {
    width: 100%;
    border-radius: 12px;
    border: 1px solid rgba(20, 24, 29, 0.2);
    background: rgba(255, 255, 255, 0.65);
    text-align: left;
    padding: 0.38rem 0.5rem;
    cursor: pointer;
    display: flex;
    flex-direction: column;
