}

.fontChipPreview {
    font-size: 0.94rem;
    color: #0f141b;
}

.aspectToggle {
    display: inline-flex;
    gap: 0.34rem;
}

.ambientLight {
    position: absolute;
    inset: 0;
    pointer-events: none;
    z-index: 0;
    border-radius: 18px;
    background: radial-gradient(
        320px circle at var(--cursor-x, 50%) var(--cursor-y, 50%),
        rgba(255, 223, 186, 0.18),
        transparent 70%
    );
    mix-blend-mode: overlay;
    opacity: var(--cursor-opacity, 0);
    transition: opacity 0.4s ease;
}

.isDark .ambientLight {
    background: radial-gradient(
        320px circle at var(--cursor-x, 50%) var(--cursor-y, 50%),
        rgba(140, 180, 255, 0.14),
        transparent 70%
    );
    mix-blend-mode: soft-light;
}

.minimapContainer {
    position: absolute;
    left: 0.7rem;
    bottom: 0.7rem;
    z-index: 2;
    border-radius: 8px;
    border: 1px solid rgba(255, 255, 255, 0.45);
    background: rgba(247, 241, 231, 0.55);
    backdrop-filter: blur(10px) saturate(120%);
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.12);
    cursor: crosshair;
    overflow: hidden;
}

.minimapDark {
    border-color: rgba(255, 255, 255, 0.18);
    background: rgba(20, 27, 35, 0.55);
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.32);
}

.minimapViewport {
    position: absolute;
    border: 1.5px solid #5ad39f;
    background: rgba(90, 211, 159, 0.12);
    border-radius: 2px;
    cursor: grab;
    box-sizing: border-box;
}

.minimapViewport:active {
    cursor: grabbing;
}

@keyframes ambientPulse {
    0% {
        opacity: 0.5;
    }
    50% {
        opacity: 0.84;
    }
    100% {
        opacity: 0.5;
    }
}

/* ── Mobile (<=820px) ── */

@media (max-width: 820px) {
    .editorLayout {
        flex-direction: column;
    }

    .sideToolbar {
        position: fixed;
        left: 0;
        top: 50%;
        transform: translateY(-50%);
        z-index: 26;
        width: 48px;
        border-radius: 0 16px 16px 0;
        display: none;
    }

    .sideToolbar.sideToolbarOpen {
        display: flex;
    }

    .sideToolbarToggle {
        display: flex;
        align-items: center;
        justify-content: center;
        position: fixed;
        left: 0;
        top: 50%;
        transform: translateY(-50%);
        z-index: 25;
        width: 24px;
        height: 56px;
        border-radius: 0 10px 10px 0;
        border: 1px solid var(--dock-border);
        border-left: none;
        background: var(--dock-bg);
        backdrop-filter: blur(10px);
        cursor: pointer;
        color: color-mix(in srgb, var(--atelier-ink) 65%, transparent);
        font-size: 0.72rem;
        padding: 0;
        line-height: 1;
    }

    .contextPanel {
        position: fixed;
        bottom: 0;
        left: 0;
        right: 0;
        width: auto;
        max-height: 50vh;
        z-index: 26;
        border-radius: 18px 18px 0 0;
        padding: 0.65rem;
        overflow-y: auto;
    }

    .viewerRoot {
        padding-bottom: 0.9rem;
    }

    .sizeRange {
        width: 100%;
    }
}

@media (max-width: 820px) {
    .toolbarDock {
        position: fixed;
        left: 0.5rem;
        right: 0.5rem;
        width: auto;
        transform: none;
        bottom: max(0.6rem, env(safe-area-inset-bottom));
        z-index: 1212;
    }

    .toolbarDockInCv {
        left: 0;
        right: 0;
        width: 100%;
        bottom: max(0.45rem, env(safe-area-inset-bottom));
        z-index: 121;
    }

    .toolbarPanel {
        border-radius: 18px;
        max-height: min(64vh, 520px);
        overflow: auto;
    }
}

@media (prefers-reduced-motion: reduce) {
    .stageShell::after {
        animation: none;
    }

    .toolButton,
    .secondaryButton,
    .shareButton,
    .sideToolButton {
        transition: none;
    }
}

