                <button type="button" className="search-clear-btn" onClick={handleClearSearch}>
                    Clear
                </button>
            ) : null}
            <button type="button" className="search-freedom-wall-btn" onClick={handleVisitFreedomWall}>
                Visit Freedom Wall
            </button>
